+
+    fn step(&self, state: &mut Self::State, args: &[SqliteValue]) -> fsqlite_error::Result<()> {
+        if let SqliteValue::Text(v) = &args[0] {
+            if !state.is_empty() {
+                state.push(',');
+            }
+            state.push_str(v);
+        }
