+                loop {
+                    if s.load(Ordering::Relaxed) {
+                        break;
+                    }
+                    if let Err(e) = conn.execute("BEGIN CONCURRENT;") {
+                        if e.is_transient() {
+                            rollback_best_effort(&conn);
+                            retry_count += 1;
+                            if retry_count > MAX_RETRIES {
+                                break;
+                            }
+                            thread::sleep(Duration::from_millis(RETRY_SLEEP_MS));
+                            continue;
+                        }
+                        break;
+                    }
