+fn ok(name: &str, cat: Category) -> ConformanceResult {
+    ConformanceResult {
+        test_name: name.to_owned(),
+        category: cat,
+        passed: true,
+        detail: "pass".to_owned(),
+    }
+}
+
+fn fail(name: &str, cat: Category, detail: String) -> ConformanceResult {
+    ConformanceResult {
+        test_name: name.to_owned(),
+        category: cat,
+        passed: false,
+        detail,
+    }
+}
